/* ── Helper Utilities ────────────────────────────────────────── */

/**
 * Get a semantic token value for current theme
 * @param {'outline'|'surface'|'ink'} category
 * @param {string} name  e.g. 'blueprint-1'
 * @returns {string} hex color value
 */
function ikToken(category, name) {
  const isDark = document.documentElement.getAttribute('data-theme') === 'dark'
  const theme = isDark ? IK_TOKENS.dark : IK_TOKENS.light
  return theme[category]?.[name] ?? null
}

/**
 * Get a primitive color value
 * @param {string} color  e.g. 'blueprint'
 * @param {string|number} shade  e.g. 500
 * @param {'light'|'dark'} [mode]  defaults to current theme
 * @returns {string} hex color value
 */
function ikColor(color, shade, mode) {
  const resolvedMode = mode ?? (document.documentElement.getAttribute('data-theme') === 'dark' ? 'darkMode' : 'lightMode')
  return IK_COLORS[resolvedMode]?.[color]?.[String(shade)] ?? null
}

/**
 * Inject a CSS variable override at runtime (useful for dynamic theming)
 * @param {string} varName  e.g. '--surface-menu-bar'
 * @param {string} value    e.g. '#000FCC'
 */
function ikSetVar(varName, value) {
  document.documentElement.style.setProperty(varName, value)
}

